#[cfg(test)]
#[derive(Debug)]
struct TestToken {
    token_type: TokenType,
    lexeme: &'static str,
    source_byte_start: usize,
    source_byte_end: usize,    
    logical_byte_start: usize,
    logical_byte_end: usize,    
    line: usize,
}

#[derive(Debug)]
struct TestInputAndResult<'a> {
    source: &'a str,
    expected_len: usize, 
    expected_tokens: &'static [TestToken],
    unique_tag: &'a str,
}

