fn verify_tokens(tokens: &[Token], result: &TestInputAndResult) {
    assert_eq!(tokens.len(), result.expected_len, "{} Total number of tokens", result.unique_tag);

    for (index, token) in tokens.iter().enumerate() {
        let expected_token = &result.expected_tokens[index];

        assert_eq!(token.token_type(), expected_token.token_type, 
            "{} Token type {}", result.unique_tag, index+1);

        assert_eq!(token.lexeme(), expected_token.lexeme, 
            "{} Lexeme {}", result.unique_tag, index+1);

        assert_eq!(token.source_byte_start(), expected_token.source_byte_start, 
            "{} source_byte_start {}", result.unique_tag, index+1);

        assert_eq!(token.source_byte_end(), expected_token.source_byte_end, 
            "{} source_byte_end {}", result.unique_tag, index+1);

        assert_eq!(token.logical_byte_start(), expected_token.logical_byte_start, 
            "{} logical_byte_start {}", result.unique_tag, index+1);

        assert_eq!(token.logical_byte_end(), expected_token.logical_byte_end, 
            "{} logical_byte_end {}", result.unique_tag, index+1);

        assert_eq!(token.line(), expected_token.line, 
            "{} Line {}", result.unique_tag, index+1);
    }
}

#[test]
fn test_scanner() {
    for group in TEST_SET {
        for test in *group {
            let mut scanner = Scanner::new(test.source);
            let res = scanner.scan_tokens();

            assert!(res.is_ok(), "{} should be valid", test.unique_tag);

            let tokens = res.unwrap();
            verify_tokens(&tokens, test);
        }
    }
}